diff --git a/src/__tests__/index.js b/src/__tests__/index.js
index 3971e62..6a23a12 100644
--- a/src/__tests__/index.js
+++ b/src/__tests__/index.js
@@ -5,6 +5,7 @@ import {render, mount} from 'enzyme'
 import * as jestGlamorReact from 'jest-glamor-react'
 import {oneLine} from 'common-tags'
 import glamorous from '../'
+import {PropTypes} from '../react-compat'

 import {CHANNEL} from '../constants'

@@ -278,7 +279,7 @@ test('renders a component with theme properties', () => {
     {
       color: 'red',
     },
-    (props, theme) => ({padding: theme.padding}),
+    (props, {theme}) => ({padding: theme.padding}),
   )
   expect(
     render(<Comp theme={{padding: '10px'}} />),
@@ -291,7 +292,7 @@ test('in development mode the theme is frozen and cannot be changed', () => {
     {
       color: 'red',
     },
-    (props, theme) => {
+    (props, {theme}) => {
       expect(() => {
         theme.foo = 'bar'
       }).toThrow()
@@ -309,7 +310,7 @@ test('in production mode the theme is not frozen and can be changed', () => {
     {
       color: 'red',
     },
-    (props, theme) => {
+    (props, {theme}) => {
       expect(() => {
         theme.foo = 'bar'
       }).not.toThrow()
@@ -325,7 +326,7 @@ test('passes an updated theme when theme prop changes', () => {
     {
       color: 'red',
     },
-    (props, theme) => ({padding: theme.padding}),
+    (props, {theme}) => ({padding: theme.padding}),
   )
   const wrapper = mount(<Comp theme={{padding: 10}} />)
   expect(wrapper).toMatchSnapshotWithGlamor(`with theme prop of padding 10px`)
@@ -404,3 +405,18 @@ test('can accept classNames instead of style objects', () => {
   )
   expect(render(<Comp />)).toMatchSnapshotWithGlamor()
 })
+
+test('should accept user defined contextTypes', () => {
+  const Child = glamorous.div((props, context) => ({
+    fontSize: context.fontSize,
+  }))
+  Child.contextTypes = {
+    fontSize: PropTypes.number,
+  }
+
+  const context = {
+    fontSize: 24,
+  }
+
+  expect(render(<Child />, {context})).toMatchSnapshotWithGlamor()
+})

diff --git a/src/__tests__/theme-provider.js b/src/__tests__/theme-provider.js
index 7576b3e..9266ff6 100644
--- a/src/__tests__/theme-provider.js
+++ b/src/__tests__/theme-provider.js
@@ -5,6 +5,7 @@ import * as jestGlamorReact from 'jest-glamor-react'
 import glamorous from '../'
 import ThemeProvider from '../theme-provider'
 import {CHANNEL} from '../constants'
+import {PropTypes} from '../react-compat'

 expect.extend(jestGlamorReact.matcher)
 expect.addSnapshotSerializer(jestGlamorReact.serializer)
@@ -22,7 +23,7 @@ test('renders a component with theme', () => {
     {
       color: 'red',
     },
-    (props, theme) => ({padding: theme.padding}),
+    (props, {theme}) => ({padding: theme.padding}),
   )
   expect(
     render(
@@ -51,7 +52,7 @@ test('theme properties updates get propagated down the tree', () => {
     {
       color: 'red',
     },
-    (props, theme) => ({padding: theme.padding}),
+    (props, {theme}) => ({padding: theme.padding}),
   )
   const wrapper = mount(<Parent />)
   expect(wrapper).toMatchSnapshotWithGlamor(`with theme prop of padding 10px`)
@@ -60,11 +61,11 @@ test('theme properties updates get propagated down the tree', () => {
 })

 test('merges nested themes', () => {
-  const One = glamorous.div({}, (props, {padding, margin}) => ({
+  const One = glamorous.div({}, (props, {theme: {padding, margin}}) => ({
     padding,
     margin,
   }))
-  const Two = glamorous.div({}, (props, {padding, margin}) => ({
+  const Two = glamorous.div({}, (props, {theme: {padding, margin}}) => ({
     padding,
     margin,
   }))
@@ -109,3 +110,69 @@ test('does nothing when receive same theme via props', () => {
   wrapper.setProps({theme})
   expect(wrapper).toMatchSnapshotWithGlamor(`with theme prop of margin 2px`)
 })
+
+test('does not override user defined theme contexts', () => {
+  const Child = glamorous.div((props, context) => ({
+    fontSize: context.theme.fontSize,
+  }))
+  Child.contextTypes = {
+    theme: PropTypes.object,
+  }
+
+  class Parent extends React.Component {
+    getChildContext() {
+      return {
+        theme: {fontSize: 24},
+      }
+    }
+    render() {
+      return <Child />
+    }
+  }
+
+  Parent.childContextTypes = {
+    theme: PropTypes.object,
+  }
+
+  expect(
+    render(
+      <ThemeProvider theme={{fontSize: 36}}>
+        <Parent />
+      </ThemeProvider>,
+    ),
+  ).toMatchSnapshotWithGlamor()
+})
+
+test('monkey-patches `theme` into user defined context', () => {
+  const Child = glamorous.div((props, context) => ({
+    fontSize: context.theme.fontSize,
+    color: context.userTheme.color,
+  }))
+
+  Child.contextTypes = {
+    userTheme: PropTypes.object,
+  }
+
+  class Parent extends React.Component {
+    getChildContext() {
+      return {
+        userTheme: {color: 'blue'},
+      }
+    }
+    render() {
+      return <Child />
+    }
+  }
+
+  Parent.childContextTypes = {
+    userTheme: PropTypes.object,
+  }
+
+  expect(
+    render(
+      <ThemeProvider theme={{fontSize: 36}}>
+        <Parent />
+      </ThemeProvider>,
+    ),
+  ).toMatchSnapshotWithGlamor()
+})

